const COLORS = ['teal', 'coral', 'purple', 'amber', 'pink', 'blue'];
const PLATFORM_MAP = { 6: 'PC', 130: 'Switch', 167: 'PS5', 169: 'Xbox' };
const REGION_MAP = { 1: 'Europe', 2: 'North America', 3: 'Australia', 4: 'New Zealand', 5: 'Japan', 6: 'China', 7: 'Asia', 8: 'Worldwide', 9: 'Korea', 10: 'Brazil' };
const WEBSITE_MAP = { 1: 'official', 3: 'wikipedia', 4: 'facebook', 5: 'twitter', 13: 'steam', 14: 'reddit', 16: 'epic', 17: 'gog', 18: 'discord' };
const ESRB_MAP = { 6: 'RP', 7: 'EC', 8: 'E', 9: 'E10+', 10: 'T', 11: 'M', 12: 'AO' };
const PEGI_MAP = { 1: '3', 2: '7', 3: '12', 4: '16', 5: '18' };

const raw = $input.first().json;
const list = Array.isArray(raw) ? raw : $input.all().map(i => i.json);

const games = list.map((game, i) => {
  const ts = game.first_release_date;
  const d  = new Date(ts * 1000);
  const releaseDate = d.toISOString().split('T')[0];

  const platforms = (game.platforms || [])
    .map(p => PLATFORM_MAP[p.id])
    .filter(Boolean);

  let cover = null;
  if (game.cover?.url) {
    cover = game.cover.url
      .replace('t_thumb', 't_cover_big')
      .replace(/^\/\//, 'https://');
  }

  const developers = (game.involved_companies || [])
    .filter(c => c.developer).map(c => c.company?.name).filter(Boolean);
  const publishers = (game.involved_companies || [])
    .filter(c => c.publisher).map(c => c.company?.name).filter(Boolean);

  const releases = (game.release_dates || []).map(r => ({
    date: r.human || 'TBD',
    platform: r.platform?.name || 'Unknown',
    region: REGION_MAP[r.region] || 'Worldwide'
  }));

  const websites = (game.websites || [])
    .map(w => ({ url: w.url, type: WEBSITE_MAP[w.category] || null }))
    .filter(w => w.type);

  const ageRatings = (game.age_ratings || []).map(r => {
    if (r.category === 1) return { system: 'ESRB', rating: ESRB_MAP[r.rating] || 'RP' };
    if (r.category === 2) return { system: 'PEGI', rating: PEGI_MAP[r.rating] || '?' };
    return null;
  }).filter(Boolean);

  const langMap = {};
  for (const ls of (game.language_supports || [])) {
    const lang = ls.language?.name;
    if (!lang) continue;
    if (!langMap[lang]) langMap[lang] = { language: lang, audio: false, subtitles: false, interface: false };
    const t = (ls.language_support_type?.name || '').toLowerCase();
    if (t === 'audio') langMap[lang].audio = true;
    else if (t === 'subtitles') langMap[lang].subtitles = true;
    else if (t === 'interface') langMap[lang].interface = true;
  }

  const similarGames = (game.similar_games || []).slice(0, 12).map(sg => ({
    name: sg.name,
    genres: (sg.genres || []).map(g => g.name),
    rating: sg.rating ? Math.round(sg.rating) / 10 : null
  }));

  return {
    id:                 game.id,
    slug:               game.slug,
    title:              game.name,
    url:                `https://www.igdb.com/games/${game.slug}`,
    releaseDate,
    price:              'TBD',
    platforms,
    genres:             (game.genres || []).map(g => g.name),
    hype:               game.hypes || 0,
    cover,
    color:              COLORS[i % COLORS.length],
    summary:            game.summary || null,
    developers,
    publishers,
    themes:             (game.themes || []).map(t => t.name),
    gameModes:          (game.game_modes || []).map(m => m.name),
    playerPerspectives: (game.player_perspectives || []).map(p => p.name),
    franchises:         (game.franchises || []).map(f => f.name),
    collections:        (game.collections || []).map(c => c.name),
    engine:             (game.game_engines || []).map(e => e.name),
    alternativeNames:   (game.alternative_names || []).map(a => a.name),
    releases,
    websites,
    ageRatings,
    languageSupports:   Object.values(langMap),
    similarGames
  };
});

return [{ json: { games } }];

const games   = $('Normalize Games').first().json.games;
const sha     = $('Get Current File SHA').first().json.sha;
const content = JSON.stringify(games, null, 2);
const encoded = Buffer.from(content).toString('base64');

return [{
  json: {
    message: `chore: update games.json ${new Date().toISOString().slice(0,10)}`,
    content: encoded,
    sha
  }
}];
